-- 1. FONKSİYON: Fiyat değiştiğinde yapılacak işi tanımlar
CREATE OR REPLACE FUNCTION log_fund_price_change()
    RETURNS TRIGGER AS $$
BEGIN
    -- Sadece fiyat gerçekten değişmişse (Eski != Yeni) kayıt atar
    IF (OLD.current_price IS DISTINCT FROM NEW.current_price) THEN
        INSERT INTO fund_price_history (fund_code, price, price_date)
        VALUES (NEW.fund_code, NEW.current_price, CURRENT_TIMESTAMP);
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- 2. TRIGGER: Bu fonksiyonu 'funds' tablosundaki her UPDATE sonrası çalıştırır
DROP TRIGGER IF EXISTS trg_fund_price_update ON funds;
CREATE TRIGGER trg_fund_price_update
    AFTER UPDATE ON funds
    FOR EACH ROW
EXECUTE FUNCTION log_fund_price_change();
